cards_data.update(wands_data)
cards_data.update(cups_data)
cards_data.update(swords_data)
cards_data.update(pentacles_data)

# ========== ФУНКЦИИ БОТА ==========
async def send_card(update: Update, chat_id: int, card_num: int, reply_to_message_id: int = None):
    """Отправляет карту с картинкой (если есть)"""
    card = cards_data[card_num]
    caption = (
        f"🎴 **{card['name']}**\n\n"
        f"✨ **Значение:** {card['desc']}\n\n"
        f"{card['meaning']}\n\n"
        f"📖 **Совет:** {card['advice']}"
    )
    
    image_path = Path(CARDS_FOLDER) / f"{card_num}.jpg"
    try:
        if image_path.exists():
            with open(image_path, 'rb') as photo:
                await update.get_bot().send_photo(
                    chat_id=chat_id,
                    photo=photo,
                    caption=caption,
                    parse_mode="Markdown",
                    reply_to_message_id=reply_to_message_id
                )
        else:
            await update.get_bot().send_message(
                chat_id=chat_id,
                text=caption,
                parse_mode="Markdown",
                reply_to_message_id=reply_to_message_id
            )
    except Exception as e:
        print(f"Ошибка при отправке: {e}")
        await update.get_bot().send_message(
            chat_id=chat_id,
            text=caption,
            parse_mode="Markdown",
            reply_to_message_id=reply_to_message_id
        )

async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    keyboard = [
        [InlineKeyboardButton("🎲 Случайная карта", callback_data="random")],
        [InlineKeyboardButton("📖 Помощь", callback_data="help")]
    ]
    reply_markup = InlineKeyboardMarkup(keyboard)
    welcome_text = (
        "✨ **Оракул Таро** ✨\n\n"
        "Привет! Я бот Елены, авторской системы трансформации.\n\n"
        "🔮 **Как получить карту:**\n"
        "• Напиши число от 1 до 78\n"
        "• Или нажми кнопку «Случайная карта»\n"
        "• Или отправь /random\n\n"
        "💫 В канале просто пиши число в комментариях!\n\n"
        "Твоя карта уже ждёт 🃏"
    )
    await update.message.reply_text(welcome_text, parse_mode="Markdown", reply_markup=reply_markup)

async def help_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    help_text = (
        "📖 **Как пользоваться ботом**\n\n"
        "**В личных сообщениях:**\n"
        "• Напиши число 1-78\n"
        "• Отправь /random\n"
        "• Или нажми кнопку\n\n"
        "**В канале:**\n"
        "• Пиши число в комментариях\n"
        "• Или слово «рандом»\n\n"
        "Каждая карта содержит описание, значение в прямом и перевёрнутом положении, а также совет на неделю.\n\n"
        "🌿 Удачной недели!"
    )
    if update.message:
        await update.message.reply_text(help_text, parse_mode="Markdown")
    elif update.callback_query:
        await update.callback_query.message.reply_text(help_text, parse_mode="Markdown")

async def random_card(update: Update, context: ContextTypes.DEFAULT_TYPE):
    card_num = random.randint(1, 78)
    if update.message:
        chat_id = update.message.chat_id
        reply_id = update.message.message_id
        await send_card(update, chat_id, card_num, reply_id)
    elif update.callback_query:
        chat_id = update.callback_query.message.chat_id
        reply_id = update.callback_query.message.message_id
        await send_card(update, chat_id, card_num, reply_id)
        await update.callback_query.answer()

async def handle_message(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text.strip().lower()
    chat_id = update.message.chat_id
    reply_id = update.message.message_id
    
    if text in ["рандом", "random", "/random"]:
        card_num = random.randint(1, 78)
        await send_card(update, chat_id, card_num, reply_id)
        return
    
    if text.isdigit():
        num = int(text)
        if 1 <= num <= 78:
            await send_card(update, chat_id, num, reply_id)
        else:
            await update.message.reply_text("Пожалуйста, введите число от 1 до 78. Или напишите «рандом» для случайной карты.")
    else:
        # Игнорируем обычные сообщения
        pass

async def button_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    if query.data == "random":
        card_num = random.randint(1, 78)
        await send_card(update, query.message.chat_id, card_num, query.message.message_id)
    elif query.data == "help":
        await help_command(update, context)

# ========== ЗАПУСК ==========
def main():
    app = Application.builder().token(TOKEN).build()
    
    app.add_handler(CommandHandler("start", start))
    app.add_handler(CommandHandler("help", help_command))
    app.add_handler(CommandHandler("random", random_card))
    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, handle_message))
    app.add_handler(CallbackQueryHandler(button_callback))
    
    print("✨ Бот Оракул Таро запущен!")
    print("Работает в личных сообщениях и каналах.")
    app.run_polling()

if __name__ == "__main__":
    main()
